from dataclasses import dataclass, field
from typing import Callable

@dataclass
class WorldState:
    facts: dict = field(default_factory=dict)

    def get(self, key, default=None):
        return self.facts.get(key, default)

    def set(self, key, value):
        self.facts[key] = value

    def copy(self):
        return WorldState(facts=dict(self.facts))

@dataclass
class Action:
    name: str
    precondition: Callable[[WorldState], bool]
    effect: Callable[[WorldState], WorldState]   # returns new state
    cost: float = 1.0

class GoalDirectedAgent:
    def __init__(self, goal_test, actions, max_steps=50):
        self.goal_test = goal_test
        self.actions = actions
        self.max_steps = max_steps
        self.history = []

    def run(self, initial_state):
        state = initial_state.copy()
        for step in range(self.max_steps):
            if self.goal_test(state):
                print('Goal achieved in ' + str(step) + ' steps')
                return state, True
            action = self._select_action(state)
            if action is None:
                print('No applicable action -- stuck')
                return state, False
            print('Step ' + str(step+1) + ': ' + action.name)
            state = action.effect(state)
            self.history.append(action.name)
        print('Budget exhausted after ' + str(self.max_steps) + ' steps')
        return state, False

    def _select_action(self, state):
        # Return first applicable action (greedy -- real agents use planning)
        for action in self.actions:
            if action.precondition(state):
                return action
        return None

# Define actions for a test-coverage improvement task
actions = [
    Action(
        name='write_unit_tests',
        precondition=lambda s: s.get('coverage', 0) < 80,
        effect=lambda s: (s.set('coverage', min(80, s.get('coverage', 0) + 20)) or s),
    ),
    Action(
        name='fix_failing_tests',
        precondition=lambda s: not s.get('tests_pass', False),
        effect=lambda s: (s.set('tests_pass', True) or s),
    ),
    Action(
        name='update_docs',
        precondition=lambda s: not s.get('docs_current', False),
        effect=lambda s: (s.set('docs_current', True) or s),
    ),
]

def goal_test(state):
    return (
        state.get('tests_pass', False) and
        state.get('coverage', 0) >= 80 and
        state.get('docs_current', False)
    )

initial = WorldState({'tests_pass': False, 'coverage': 42, 'docs_current': False})
agent = GoalDirectedAgent(goal_test=goal_test, actions=actions)
final_state, achieved = agent.run(initial)

from dataclasses import dataclass, field
from typing import Optional

@dataclass
class GoalNode:
    description: str
    test: object = None                  # callable(state) -> bool
    children: list = field(default_factory=list)  # subgoals
    is_leaf: bool = False

    def achieved(self, state):
        if self.is_leaf:
            return self.test(state) if self.test else False
        return all(child.achieved(state) for child in self.children)

def build_goal_tree():
    return GoalNode(
        description='Ship the auth feature',
        children=[
            GoalNode(
                description='Implementation complete',
                children=[
                    GoalNode('login endpoint written', is_leaf=True,
                             test=lambda s: s.get('login_impl', False)),
                    GoalNode('logout endpoint written', is_leaf=True,
                             test=lambda s: s.get('logout_impl', False)),
                ]
            ),
            GoalNode(
                description='Quality gates pass',
                children=[
                    GoalNode('tests pass', is_leaf=True,
                             test=lambda s: s.get('tests_pass', False)),
                    GoalNode('coverage >= 80', is_leaf=True,
                             test=lambda s: s.get('coverage', 0) >= 80),
                ]
            ),
        ]
    )

tree = build_goal_tree()
state = {'login_impl': True, 'logout_impl': True, 'tests_pass': True, 'coverage': 85}
print('Top-level goal achieved:', tree.achieved(state))

state2 = {'login_impl': True, 'logout_impl': False, 'tests_pass': False, 'coverage': 60}
print('Top-level goal achieved:', tree.achieved(state2))
for child in tree.children:
    print('  ' + child.description + ': ' + str(child.achieved(state2)))

import time

class BudgetedGoalAgent:
    def __init__(self, goal_test, actions, max_steps=50, max_seconds=300):
        self.goal_test = goal_test
        self.actions = actions
        self.max_steps = max_steps
        self.max_seconds = max_seconds
        self.action_log = []
        self.stall_detector = {}

    def run(self, state):
        start_time = time.time()
        state = dict(state)   # work on a copy

        for step in range(self.max_steps):
            # Time budget check
            elapsed = time.time() - start_time
            if elapsed > self.max_seconds:
                return state, False, 'time budget exceeded (' + str(round(elapsed)) + 's)'

            # Goal check
            if self.goal_test(state):
                return state, True, 'goal achieved in ' + str(step) + ' steps'

            # Stall detection: if state has not changed in 5 steps, stop
            state_key = str(sorted(state.items()))
            self.stall_detector[state_key] = self.stall_detector.get(state_key, 0) + 1
            if self.stall_detector[state_key] > 5:
                return state, False, 'stalled: state unchanged for 5 steps'

            # Select and apply action
            action = self._select(state)
            if action is None:
                return state, False, 'no applicable action'

            state = action(state)
            self.action_log.append({'step': step, 'state': dict(state)})

        return state, False, 'step budget exhausted (' + str(self.max_steps) + ' steps)'

    def _select(self, state):
        for action in self.actions:
            if action.get('precondition', lambda s: True)(state):
                return action['effect']
        return None
